import { Atom } from "@effect-atom/atom"
import { Option } from "effect"
import { ContractAddress, TxHash } from "../services/types"

export type DeployStep =
  | { step: "idle" }
  | { step: "generating-keypair" }
  | { step: "packing" }
  | { step: "computing-address" }
  | { step: "awaiting-funds"; address: ContractAddress }
  | { step: "deploying"; address: ContractAddress }
  | { step: "deployed"; address: ContractAddress; txHash: TxHash }
  | { step: "error"; message: string }

export const deployStepAtom = Atom.make<DeployStep>({ step: "idle" }).pipe(
  Atom.keepAlive,
)

export const deployedAddressAtom = Atom.make<Option.Option<ContractAddress>>(Option.none()).pipe(
  Atom.keepAlive,
)

export const deployTxHashAtom = Atom.make<Option.Option<TxHash>>(Option.none()).pipe(
  Atom.keepAlive,
)

import { Config, Effect } from "effect"
import { RpcProvider, Account, hash, CallData, stark } from "starknet"
import {
  StarknetRpcError,
  AccountDeployError,
} from "./errors"
import { TxHash, ContractAddress } from "./types"
import type { PackedPublicKey } from "./types"

// FalconAccount class hash — declared on Starknet Sepolia
// TODO: replace with actual class hash after running: ./bin/declare-sepolia.sh --account sepolia-deployer
const FALCON_ACCOUNT_CLASS_HASH = "0x0"

/** STRK token contract address (same on mainnet and Sepolia) */
export const STRK_TOKEN_ADDRESS =
  "REDACTED"

export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      const provider = new RpcProvider({ nodeUrl: rpcUrl })

      const computeDeployAddress = Effect.fn("Starknet.computeDeployAddress")(
        function* (packedPk: PackedPublicKey) {
          const constructorCalldata = CallData.compile({
            pk_packed: packedPk.slots,
          })
          const salt = stark.randomAddress()
          const address = hash.calculateContractAddressFromHash(
            salt,
            FALCON_ACCOUNT_CLASS_HASH,
            constructorCalldata,
            0,
          )
          return {
            address: ContractAddress.make(address),
            salt,
          }
        },
      )

      const getBalance = Effect.fn("Starknet.getBalance")(
        function* (address: string) {
          return yield* Effect.tryPromise({
            try: async () => {
              const result = await provider.callContract({
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "balanceOf",
                calldata: [address],
              })
              return BigInt(result[0])
            },
            catch: (error) =>
              new StarknetRpcError({ message: String(error), code: -1 }),
          })
        },
      )

      const deployAccount = Effect.fn("Starknet.deployAccount")(
        function* (
          packedPk: PackedPublicKey,
          privateKey: string,
          salt: string,
        ) {
          const constructorCalldata = CallData.compile({
            pk_packed: packedPk.slots,
          })
          const address = hash.calculateContractAddressFromHash(
            salt,
            FALCON_ACCOUNT_CLASS_HASH,
            constructorCalldata,
            0,
          )

          // starknet v9 Account constructor takes a single AccountOptions object
          const account = new Account({ provider, address, signer: privateKey })

          const result = yield* Effect.tryPromise({
            try: () =>
              account.deployAccount({
                classHash: FALCON_ACCOUNT_CLASS_HASH,
                constructorCalldata,
                addressSalt: salt,
                contractAddress: address,
              }),
            catch: (error) =>
              new AccountDeployError({ message: String(error) }),
          })

          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(result.transaction_hash),
            catch: (error) =>
              new AccountDeployError({
                message: `Tx failed: ${error}`,
                txHash: result.transaction_hash,
              }),
          })

          return {
            txHash: TxHash.make(result.transaction_hash),
            address: ContractAddress.make(result.contract_address),
          }
        },
      )

      const waitForTx = Effect.fn("Starknet.waitForTx")(
        function* (txHash: string) {
          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(txHash),
            catch: (error) =>
              new StarknetRpcError({ message: String(error), code: -1 }),
          })
        },
      )

      return {
        computeDeployAddress,
        getBalance,
        deployAccount,
        waitForTx,
        provider,
      }
    }),
  },
) {}

/**
 * Tests for StarknetService — effect-services category.
 *
 * Strategy: StarknetService is tested via Layer.succeed mocks so no live
 * RPC connection is needed. This covers the contract (method signatures,
 * error types, Exit values) without hitting mainnet.
 *
 * Additionally, the real StarknetService is tested for computeDeployAddress
 * (pure computation — no network call) using ConfigProvider to inject the
 * RPC URL.
 *
 * Coverage requirements:
 * - Every service method must have at least one success and one failure test
 * - StarknetRpcError, AccountDeployError must be producible by the service
 */

import { describe, it, expect } from "bun:test"
import { Effect, Exit, Layer, ConfigProvider } from "effect"
import { StarknetService } from "../../services/StarknetService"
import { StarknetRpcError, AccountDeployError } from "../../services/errors"
import type { PackedPublicKey, TxHash, ContractAddress } from "../../services/types"

// ---------------------------------------------------------------------------
// Mock StarknetService helpers
// Use `as any` for mock service objects because test mocks intentionally
// include error-producing methods that differ from the inferred success-only types.
// ---------------------------------------------------------------------------

const mockAddress = "0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7" as ContractAddress
const mockTxHash = "0x7f3e2a1b9c4d5e6f" as TxHash

// Success mock: all methods return successful Effects
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const makeSuccessService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed({ address: mockAddress, salt: "0xdeadbeef" }),
    getBalance: (_addr: string) => Effect.succeed(BigInt("1000000000000000000")),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.succeed({ txHash: mockTxHash, address: mockAddress }),
    waitForTx: (_tx: string) => Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

// Failing mock: all methods return failing Effects with typed errors
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const makeFailingService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "mock rpc error", code: -1 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "balance fetch failed", code: -32000 })),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.fail(new AccountDeployError({ message: "deploy rejected" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "tx timeout", code: -1 })),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/** Run an effect provided with a specific StarknetService mock layer */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> {
  return Effect.runPromiseExit(
    effect.pipe(Effect.provide(serviceLayer)),
  )
}

// ---------------------------------------------------------------------------
// computeDeployAddress
// ---------------------------------------------------------------------------

describe("StarknetService.computeDeployAddress (mocked)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  it("succeeds and returns a ContractAddress string", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(mockPk),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value.address).toBe("string")
      expect(exit.value.address.startsWith("0x")).toBe(true)
    }
  })

  it("fails with StarknetRpcError when service fails", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(mockPk),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// getBalance
// ---------------------------------------------------------------------------

describe("StarknetService.getBalance (mocked)", () => {
  it("succeeds and returns a bigint balance", async () => {
    const exit = await runWith(
      StarknetService.getBalance("0x1234"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value).toBe("bigint")
      expect(exit.value).toBe(BigInt("1000000000000000000"))
    }
  })

  it("fails with StarknetRpcError when RPC call fails", async () => {
    const exit = await runWith(
      StarknetService.getBalance("0xdeadbeef"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// deployAccount
// ---------------------------------------------------------------------------

describe("StarknetService.deployAccount (mocked)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  it("succeeds and returns txHash and address", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPk, "0xprivkey", "0xsalt"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.txHash).toBe(mockTxHash)
      expect(exit.value.address).toBe(mockAddress)
    }
  })

  it("fails with AccountDeployError when deployment is rejected", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPk, "0xprivkey", "0xsalt"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
    }
  })
})

// ---------------------------------------------------------------------------
// waitForTx
// ---------------------------------------------------------------------------

describe("StarknetService.waitForTx (mocked)", () => {
  it("succeeds (returns void) when transaction confirms", async () => {
    const exit = await runWith(
      StarknetService.waitForTx("0xabc123"),
      makeSuccessService(),
    )
    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("fails with StarknetRpcError when tx times out", async () => {
    const exit = await runWith(
      StarknetService.waitForTx("0xdeadbeef"),
      makeFailingService(),
    )
    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

// ---------------------------------------------------------------------------
// Real StarknetService: computeDeployAddress (pure computation, no network)
// ---------------------------------------------------------------------------

describe("StarknetService.computeDeployAddress (real implementation)", () => {
  const mockPk: PackedPublicKey = {
    slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
  }

  const withTestConfig = ConfigProvider.fromMap(
    new Map([["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"]]),
  )

  it("returns a hex string address (pure computation, no RPC call)", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(withTestConfig)),
      ),
    )
    // computeDeployAddress is pure (hash + CallData only), should succeed
    // even with a fake RPC URL because no network call is made
    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(typeof exit.value.address).toBe("string")
      expect(typeof exit.value.salt).toBe("string")
    }
  })
})

// ---------------------------------------------------------------------------
// StarknetService: fails when Config is missing
// ---------------------------------------------------------------------------

describe("StarknetService: initialization failure", () => {
  it("StarknetService.Default fails gracefully when Config is missing", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress({
        slots: Array.from({ length: 29 }, () => "0x0"),
      }).pipe(
        Effect.provide(StarknetService.Default),
        // Provide an empty ConfigProvider to prevent bun from loading .env.local —
        // this simulates the "no config available" scenario the test describes
        Effect.provide(Layer.setConfigProvider(ConfigProvider.fromMap(new Map()))),
      ),
    )
    // Should fail because NEXT_PUBLIC_STARKNET_RPC_URL is not in the empty config
    expect(Exit.isFailure(exit)).toBe(true)
  })
})

/**
 * Integration tests for Account Deploy Flow — account-deploy category.
 *
 * Tests the 5-step mainnet deployment flow:
 *   1. generating-keypair  (Falcon keygen via FalconService)
 *   2. packing             (pack public key to felt252 slots)
 *   3. computing-address   (pure hash + CallData computation)
 *   4. awaiting-funds      (balance check loop via getBalance)
 *   5. deploying           (broadcastAccount + waitForTx)
 *
 * Strategy:
 * - All StarknetService calls use Layer.succeed mocks — no live RPC
 * - Atoms are driven via Registry.make() for isolated state tracking
 * - An orchestrated Effect drives state transitions the same way
 *   AccountDeployFlow component will drive them in production
 * - Every service method has success + failure coverage
 * - Every Schema.TaggedError appears in at least one failure case
 *
 * Coverage requirements:
 * - computeDeployAddress: success, failure
 * - getBalance: success (funded), success (zero = awaiting funds), failure
 * - deployAccount: success, failure (no txHash), failure (with txHash)
 * - waitForTx: success, failure
 * - InsufficientFundsError: constructable, matchable, catchTag
 * - AccountDeployError: with/without txHash in deploy context
 * - Orchestrated flow: full happy-path, error propagation
 */

import { describe, it, expect, beforeEach } from "bun:test"
import { Effect, Exit, Layer, Option, Cause, ConfigProvider } from "effect"
import { Registry } from "@effect-atom/atom"

import { StarknetService } from "../../services/StarknetService"
import {
  StarknetRpcError,
  AccountDeployError,
  InsufficientFundsError,
} from "../../services/errors"
import {
  TxHash,
  ContractAddress,
} from "../../services/types"
import type { PackedPublicKey } from "../../services/types"
import type { DeployStep } from "../../atoms/starknet"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
} from "../../atoms/starknet"

// ---------------------------------------------------------------------------
// Test fixtures
// ---------------------------------------------------------------------------

const MOCK_ADDRESS = ContractAddress.make("0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7")
const MOCK_TX_HASH = TxHash.make("0x7f3e2a1b9c4d5e6f0a1b2c3d4e5f6a7b")
const MOCK_PACKED_PK: PackedPublicKey = {
  slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
}
const MOCK_PRIVATE_KEY = "0xdeadbeefcafebabe1234567890abcdef"
const FUNDED_BALANCE = BigInt("1000000000000000000") // 1 STRK
const ZERO_BALANCE = BigInt(0)

// ---------------------------------------------------------------------------
// Mock Layer builders
// ---------------------------------------------------------------------------

/**
 * Happy-path StarknetService: all methods succeed.
 */
const makeSuccessLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed({ address: MOCK_ADDRESS, salt: "0xdeadbeef" }),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.succeed({ txHash: MOCK_TX_HASH, address: MOCK_ADDRESS }),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Zero-balance service: getBalance returns 0 (account not yet funded).
 */
const makeZeroBalanceLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed({ address: MOCK_ADDRESS, salt: "0xdeadbeef" }),
    getBalance: (_addr: string) =>
      Effect.succeed(ZERO_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.fail(new AccountDeployError({ message: "should not be reached" })),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Deploy failure: deployAccount fails without txHash.
 */
const makeDeployFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed({ address: MOCK_ADDRESS, salt: "0xdeadbeef" }),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.fail(new AccountDeployError({ message: "insufficient fee" })),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * Deploy failure: deployAccount fails WITH a txHash (tx was broadcast but reverted).
 */
const makeDeployRevertedLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.succeed({ address: MOCK_ADDRESS, salt: "0xdeadbeef" }),
    getBalance: (_addr: string) =>
      Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.fail(
        new AccountDeployError({
          message: "transaction reverted",
          txHash: MOCK_TX_HASH,
        }),
      ),
    waitForTx: (_tx: string) =>
      Effect.succeed(undefined as void),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/**
 * RPC failure: computeDeployAddress fails (simulates RPC down at address computation).
 */
const makeRpcFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -1 })),
    deployAccount: (_pk: PackedPublicKey, _sk: string, _salt: string) =>
      Effect.fail(new AccountDeployError({ message: "connection refused" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "timeout", code: -32003 })),
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    provider: {} as any,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  } as any)

/** Run an effect provided with a specific StarknetService mock layer */
async function runWith<A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> {
  return Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))
}

